function wrapText(text, maxChars) {
  var words = text.split(" ");
  var lines = [];
  var currentLine = "";
  for (var i = 0; i < words.length; i++) {
    if ((currentLine + " " + words[i]).length > maxChars) {
      lines.push(currentLine);
      currentLine = words[i];
    } else {
      currentLine = currentLine === "" ? words[i] : currentLine + " " + words[i];
    }
  }
  if (currentLine !== "") {
    lines.push(currentLine);
  }
  return lines.join("\r");
